import { evaluateAchievements } from '../../engine/MetaProgression';
import { EngineLogger } from '../../engine/EngineLogger.js';

export function processMetaProgression(engine, team, pos) {
  try {
    const stats = {
      titlesWon: engine.legacy?.titles?.length || 0,
      cupsWon: engine.legacy?.titles?.filter(t => t.includes('Copa'))?.length || 0,
      youthPromoted: team.squad.filter(p => p.isYouth).length,
      giantKills: engine.managerStats?.giantKills || 0,
      crisisSaves: engine.managerStats?.crisisSaves || 0,
      consecutiveSeasons: engine.seasonNumber || 1,
      transferProfit: engine.managerStats?.transferProfit || 0,
      longestUnbeaten: engine.managerStats?.longestUnbeaten || 0,
      consecutiveTitles: engine.managerStats?.consecutiveTitles || 0
    };
    const result = evaluateAchievements(stats);
    if (result.newlyUnlocked.length > 0) {
      result.newlyUnlocked.forEach(ach => {
        engine.weekEvents.push(`${ach.emoji} CONQUISTA DESBLOQUEADA: ${ach.name} — ${ach.description}`);
      });
      engine.metaUnlocked = result.allUnlocked;
    }
  } catch (err) {
    EngineLogger.capture(err, 'SeasonProcessor._processMetaProgression', {
      season: engine.seasonNumber
    });
  }
}

/**
 * Baseline Stats Runner — SPEC Etapa 5 SDD
 *
 * Simula N temporadas e dump métricas pra validar hipóteses de balance.
 * Roda direto via node tools/baseline-stats.js [N]
 */

import { Engine } from '../src/engine/engine.js';
import { setGlobalSeed } from '../src/engine/rng.js';

const N = parseInt(process.argv[2] || '20', 10);

const results = {
    runs: N,
    perSeason: [],
    aggregate: {
        totalWins: 0,
        totalDraws: 0,
        totalLosses: 0,
        winStreakMax: 0,
        lossStreakMax: 0,
        finalPositionAvg: 0,
        seasonsCompleted: N,
    },
};

let winStreakMaxOverall = 0;
let lossStreakMaxOverall = 0;
let finalPositionSum = 0;

console.log(`=== Baseline Stats Runner: ${N} seasons ===\n`);

for (let i = 0; i < N; i++) {
    setGlobalSeed(1000 + i); // deterministic per-run
    const engine = new Engine();
    engine.initGame(`Tecnico${i}`, 1, 'manager', 'livre');

    let currentWinStreak = 0;
    let currentLossStreak = 0;
    let seasonWinStreakMax = 0;
    let seasonLossStreakMax = 0;

    // Run 1 full season (38 weeks)
    for (let w = 0; w < 38; w++) {
        try {
            engine.weekEvents = [];
            engine.doTraining('fitness');
            engine.advanceWeek();
            // Detectar resultado da semana via managerStats delta
            const wins = engine.managerStats?.wins || 0;
            const draws = engine.managerStats?.draws || 0;
            const losses = engine.managerStats?.losses || 0;
            const total = wins + draws + losses;
            // streak tracking via rollingForm length grows
            const form = engine.managerStats?.rollingForm || [];
            const last = form[form.length - 1];
            if (last === 'W') { currentWinStreak++; currentLossStreak = 0; }
            else if (last === 'L') { currentLossStreak++; currentWinStreak = 0; }
            else if (last === 'D') { currentWinStreak = 0; currentLossStreak = 0; }
            if (currentWinStreak > seasonWinStreakMax) seasonWinStreakMax = currentWinStreak;
            if (currentLossStreak > seasonLossStreakMax) seasonLossStreakMax = currentLossStreak;
        } catch (e) {
            // tournaments may not be initialized; skip
            break;
        }
    }

    const stats = engine.managerStats || { wins: 0, draws: 0, losses: 0 };
    let finalPos = 0;
    try {
        const team = engine.getTeam(1);
        if (team && typeof engine.getStandings === 'function') {
            const standings = engine.getStandings(team.zone, team.division);
            const myRow = standings.findIndex(s => s.teamId === team.id);
            if (myRow >= 0) finalPos = myRow + 1;
        }
    } catch { /* defensive */ }

    const seasonData = {
        run: i + 1,
        wins: stats.wins,
        draws: stats.draws,
        losses: stats.losses,
        winStreakMax: seasonWinStreakMax,
        lossStreakMax: seasonLossStreakMax,
        finalPosition: finalPos,
    };
    results.perSeason.push(seasonData);

    results.aggregate.totalWins += stats.wins;
    results.aggregate.totalDraws += stats.draws;
    results.aggregate.totalLosses += stats.losses;
    if (seasonWinStreakMax > winStreakMaxOverall) winStreakMaxOverall = seasonWinStreakMax;
    if (seasonLossStreakMax > lossStreakMaxOverall) lossStreakMaxOverall = seasonLossStreakMax;
    finalPositionSum += finalPos;

    if ((i + 1) % 10 === 0) {
        console.log(`  Run ${i + 1}/${N}: W${stats.wins} D${stats.draws} L${stats.losses} pos${finalPos} maxStreakW=${seasonWinStreakMax} L=${seasonLossStreakMax}`);
    }
}

results.aggregate.winStreakMax = winStreakMaxOverall;
results.aggregate.lossStreakMax = lossStreakMaxOverall;
results.aggregate.finalPositionAvg = N > 0 ? (finalPositionSum / N) : 0;

const avgWins = results.aggregate.totalWins / N;
const avgDraws = results.aggregate.totalDraws / N;
const avgLosses = results.aggregate.totalLosses / N;

console.log('\n=== Aggregate ===');
console.log(`  Avg per season: W ${avgWins.toFixed(2)} | D ${avgDraws.toFixed(2)} | L ${avgLosses.toFixed(2)}`);
console.log(`  Max win streak overall: ${winStreakMaxOverall}`);
console.log(`  Max loss streak overall: ${lossStreakMaxOverall}`);
console.log(`  Avg final position: ${results.aggregate.finalPositionAvg.toFixed(2)}`);

// Calculate variance
const finalPositions = results.perSeason.map(s => s.finalPosition).filter(p => p > 0);
const meanPos = finalPositions.reduce((a, b) => a + b, 0) / finalPositions.length;
const variancePos = finalPositions.reduce((sum, p) => sum + Math.pow(p - meanPos, 2), 0) / finalPositions.length;
console.log(`  Final position variance: ${variancePos.toFixed(2)}`);

results.aggregate.variance = variancePos;

console.log('\nDump:');
console.log(JSON.stringify(results.aggregate, null, 2));

import fs from 'fs';
import path from 'path';
import chalk from 'chalk';
import ora from 'ora';
import { searchTeam } from './api.js';

// Precisamos importar as DBs do jogo principal
// Para facilitar no ES Modules sem setup complexo, vamos ler e fazer um parse basico (ou usar eval/import)
import { BrazilDB } from '../../../src/engine/db/brazil.js';
import { EuropeDB } from '../../../src/engine/db/europe.js';
import { SouthAmericaDB } from '../../../src/engine/db/south_america.js';

async function main() {
    console.log(chalk.blue.bold('🔍 Mapeamento Automático de Times no Sofascore'));

    // Coletar todos os times do jogo
    const allTeams = [];
    Object.entries(BrazilDB).forEach(([div, teams]) => {
        teams.forEach(t => allTeams.push({ name: t.name, tier: parseInt(div), zone: 'BRA' }));
    });
    Object.entries(EuropeDB).forEach(([zone, divs]) => {
        Object.entries(divs).forEach(([div, teams]) => {
            teams.forEach(t => allTeams.push({ name: t.name, tier: parseInt(div), zone }));
        });
    });
    Object.entries(SouthAmericaDB).forEach(([zone, divs]) => {
        Object.entries(divs).forEach(([div, teams]) => {
            teams.forEach(t => allTeams.push({ name: t.name, tier: parseInt(div), zone }));
        });
    });

    console.log(`Total de times na base do OléFUT: ${allTeams.length}\n`);

    const teamsMap = {};
    const unmatched = [];
    const nameReplacements = []; // Times que o nome difere (ex: Athletico-PR -> Athletico)

    const spinner = ora('Buscando IDs...').start();

    for (const team of allTeams) {
        spinner.text = `Buscando: ${team.name}`;

        try {
            // Limpezas de nome para melhorar a busca
            let query = team.name.replace(' (URU)', '');

            const results = await searchTeam(query);

            if (results && results.length > 0) {
                // Pega o primeiro time retornado
                const match = results[0].entity;
                teamsMap[team.name] = { id: match.id, tier: team.tier };

                // Se o nome for muito diferente, marcamos para log
                if (match.name.toLowerCase() !== query.toLowerCase()) {
                    nameReplacements.push({ 
                        original: team.name, 
                        sofascore: match.name, 
                        id: match.id 
                    });
                }
            } else {
                unmatched.push(team.name);
            }
        } catch (error) {
            unmatched.push(team.name);
        }

        // Rate limit para não tomar ban
        await new Promise(r => setTimeout(r, 600));
    }

    spinner.succeed('Busca concluída!');

    // Salvar o dicionário principal
    fs.writeFileSync('./src/teams.json', JSON.stringify(teamsMap, null, 2));

    // Salvar relatórios
    const outDir = path.join(process.cwd(), 'reports');
    if (!fs.existsSync(outDir)) fs.mkdirSync(outDir);

    fs.writeFileSync(path.join(outDir, 'unmatched_teams.json'), JSON.stringify(unmatched, null, 2));
    fs.writeFileSync(path.join(outDir, 'name_differences.json'), JSON.stringify(nameReplacements, null, 2));

    console.log(chalk.green(`\n✅ ${Object.keys(teamsMap).length} times mapeados com sucesso.`));
    console.log(chalk.yellow(`⚠️  ${unmatched.length} times NÃO encontrados.`));
    console.log(chalk.cyan(`📝 Resultados salvos em ./src/teams.json e ./reports/`));
}

main().catch(console.error);

import fs from 'fs';
import path from 'path';
import chalk from 'chalk';
import ora from 'ora';
import { getTeamSquad } from './api.js';
import { mapPlayer } from './mapper.js';
import axios from 'axios';

// IDs dos principais torneios do Sofascore
const TOURNAMENTS = [
    { id: 17, name: 'Premier League', tier: 1 },
    { id: 8, name: 'LaLiga', tier: 1 },
    { id: 23, name: 'Serie A', tier: 1 },
    { id: 35, name: 'Bundesliga', tier: 1 },
    { id: 34, name: 'Ligue 1', tier: 1 },
    { id: 37, name: 'Eredivisie', tier: 2 },
    { id: 238, name: 'Primeira Liga (PT)', tier: 2 },
    { id: 297, name: 'Saudi Pro League', tier: 2 },
    { id: 18, name: 'Championship (ENG)', tier: 2 },
    { id: 54, name: 'Serie A (Equador)', tier: 3 },
    { id: 14, name: 'Liga MX', tier: 3 },
    { id: 242, name: 'J1 League', tier: 4 },
    { id: 11, name: 'Primera A (Colômbia)', tier: 3 },
];

async function getTournamentTeams(tournamentId) {
    try {
        // Obter as seasons do torneio (precisa pegar a season atual)
        const seasonsRes = await axios.get(`https://api.sofascore.com/api/v1/unique-tournament/${tournamentId}/seasons`, {
            headers: {
                'User-Agent': 'Mozilla/5.0 (Windows NT 10.0; Win64; x64) AppleWebKit/537.36 (KHTML, like Gecko) Chrome/120.0.0.0 Safari/537.36',
                'Accept': '*/*',
                'Origin': 'https://www.sofascore.com',
                'Referer': 'https://www.sofascore.com/'
            }
        });

        const currentSeason = seasonsRes.data.seasons[0];

        // Obter os times via standings (classificação)
        const standingsRes = await axios.get(`https://api.sofascore.com/api/v1/unique-tournament/${tournamentId}/season/${currentSeason.id}/standings/total`, {
            headers: {
                'User-Agent': 'Mozilla/5.0 (Windows NT 10.0; Win64; x64) AppleWebKit/537.36',
                'Accept': '*/*',
                'Origin': 'https://www.sofascore.com',
                'Referer': 'https://www.sofascore.com/'
            }
        });

        const teams = [];
        // O standings vem como um array (às vezes com grupos, às vezes corrida reta)
        const standings = standingsRes.data.standings[0].rows;
        for (const row of standings) {
            teams.push({
                id: row.team.id,
                name: row.team.name
            });
        }

        return teams;
    } catch (e) {
        console.error(`Erro ao buscar times do torneio ${tournamentId}: ${e.message}`);
        return [];
    }
}

async function main() {
    console.log(chalk.blue.bold('🌍 Iniciando Extrator Global de Ligas (Mega DB)'));

    let allGlobalPlayers = [];
    const spinner = ora('Coletando times dos torneios globais...').start();

    // 1. Pegar todos os times
    let teamsToScrape = [];
    for (const tourney of TOURNAMENTS) {
        spinner.text = `Carregando times: ${tourney.name}`;
        const teams = await getTournamentTeams(tourney.id);
        teams.forEach(t => {
            t.tier = tourney.tier; // Salva o nível técnico para gerar o OVR correto
            teamsToScrape.push(t);
        });
        await new Promise(r => setTimeout(r, 1000));
    }

    spinner.succeed(`Total de times globais mapeados: ${teamsToScrape.length}`);

    // 2. Extrair jogadores time a time
    spinner.start('Iniciando o Mega Download de jogadores...');
    let successCount = 0;
    let failCount = 0;

    for (let i = 0; i < teamsToScrape.length; i++) {
        const t = teamsToScrape[i];
        spinner.text = `Baixando [${i+1}/${teamsToScrape.length}]: ${t.name}`;

        try {
            const rawPlayers = await getTeamSquad(t.id);
            if (rawPlayers && rawPlayers.length > 0) {
                const parsed = rawPlayers.map(p => mapPlayer(p, t.name, t.tier));
                allGlobalPlayers = allGlobalPlayers.concat(parsed);
                successCount++;
            }
        } catch (error) {
            failCount++;
        }

        // Delay crucial para não tomar IP Ban
        await new Promise(r => setTimeout(r, 800));
    }

    spinner.succeed(`Sincronização global concluída!`);
    console.log(chalk.green(`✅ ${successCount} times baixados com sucesso.`));
    console.log(chalk.cyan(`👥 Total de Gringos extraídos: ${allGlobalPlayers.length}`));

    // 3. Salvar o JSON local
    const outPath = path.join(process.cwd(), 'out', 'globalPlayers.json');
    fs.writeFileSync(outPath, JSON.stringify(allGlobalPlayers, null, 2));

    console.log(chalk.yellow(`💾 Arquivo salvo em: ./out/globalPlayers.json`));
}

main().catch(console.error);
